1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	};
10	
11	type Step = {
12	  op: string;
13	  items?: Item[];
14	};
15	
16	type ScenarioInput = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	type ScenarioOutput = {
22	  results: unknown[];
23	};
24	
25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	};
33	
34	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
35	  const items = input.steps[0].items ?? [];
36	  const basePremium = items.reduce(
37	    (sum, item) => sum + BASE_PREMIUMS[item.type],
38	    0
39	  );
40	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
41	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
42	  return { results: [{ premium }] };
43	};
44

